+function findOptionTerm(usage: Usage): Extract<UsageTerm, { type: "option" }> | undefined {
+  for (const term of usage) {
+    if (term.type === "option") return term;
+    if (term.type === "optional" || term.type === "multiple") {
+      const nested = findOptionTerm(term.terms);
+      if (nested != null) return nested;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const nested = findOptionTerm(terms);
+        if (nested != null) return nested;
+      }
+    }
+  }
+  return undefined;
+}
+
+function getOptionDependency(usage: Usage): OptionDependency | undefined {
+  return findOptionTerm(usage)?.dependsOn;
+}
+
+function getStateValue(state: unknown): { provided: boolean; value: unknown } {
+  if (Array.isArray(state) && state.length === 1) {
+    return getStateValue(state[0]);
+  }
+  if (isDependencySourceState(state)) return getStateValue(state.result);
+  if (isDeferredParseState(state)) return getStateValue(state.preliminaryResult);
+  if (state != null && typeof state === "object" && "success" in state) {
+    const result = state as { readonly success: boolean; readonly value?: unknown };
+    return result.success ? { provided: true, value: result.value } : {
+      provided: false,
+      value: undefined,
+    };
+  }
+  return { provided: false, value: undefined };
+}
+
+function findDependencyField(
+  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+  option: string,
+): string | symbol | undefined {
+  for (const [field, parser] of parserPairs) {
+    if (field === option || findOptionTerm(parser.usage)?.names.includes(option as never)) {
+      return field;
+    }
+  }
+  return undefined;
+}
+
+interface DependencyEvaluation {
+  readonly satisfied: boolean;
+  readonly hasExplicitFalsyValue: boolean;
+  readonly failedCondition?: OptionDependencyCondition;
+}
+
+function evaluateOptionDependency(
+  dependency: OptionDependency,
+  state: unknown,
+  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+): DependencyEvaluation {
+  const sourceState = state != null && typeof state === "object"
+    ? state as Record<string | symbol, unknown>
+    : {};
+  const evaluate = (condition: OptionDependencyCondition): DependencyEvaluation => {
+    const field = findDependencyField(parserPairs, condition.option);
+    if (field == null) {
+      return { satisfied: false, hasExplicitFalsyValue: false, failedCondition: condition };
+    }
+    const value = getStateValue(sourceState[field]);
+    const satisfied = "value" in condition
+      ? value.provided && value.value === condition.value
+      : value.provided && Boolean(value.value);
+    return {
+      satisfied,
+      hasExplicitFalsyValue: value.provided && !Boolean(value.value),
+      ...(satisfied ? {} : { failedCondition: condition }),
+    };
+  };
+  if (dependency.anyOf != null) {
+    const evaluations = dependency.anyOf.map(evaluate);
+    const satisfied = evaluations.some((evaluation) => evaluation.satisfied);
+    return {
+      satisfied,
+      hasExplicitFalsyValue: !satisfied && evaluations.some((evaluation) => evaluation.hasExplicitFalsyValue),
+      ...(!satisfied && evaluations[0]?.failedCondition
+        ? { failedCondition: evaluations[0].failedCondition }
+        : {}),
+    };
+  }
+  if (dependency.allOf != null) {
+    const evaluations = dependency.allOf.map(evaluate);
+    const failed = evaluations.find((evaluation) => !evaluation.satisfied);
+    return {
+      satisfied: failed == null,
+      hasExplicitFalsyValue: failed?.hasExplicitFalsyValue ?? false,
+      ...(failed?.failedCondition ? { failedCondition: failed.failedCondition } : {}),
+    };
+  }
+  return dependency.option == null
+    ? { satisfied: false, hasExplicitFalsyValue: false }
+    : evaluate(dependency as OptionDependencyCondition);
+}
